-- Seed data: 800 additional everyday ingredients for a German family.
-- Nutritional values are per 100 g/ml; source is recorded in tags.
--
-- Datenqualität (bewusste Abweichung von codex/001-seed-ingredients.md):
-- Anders als bei den ursprünglichen 200 sind die Nährwerte hier pro
-- Zutaten-KATEGORIE geschätzt, nicht pro einzelner Variante individuell aus
-- BLS/USDA recherchiert — z. B. haben "Aprikose frisch/tiefgekühlt/Dose/
-- getrocknet" identische Werte, obwohl sie real unterschiedlich sind
-- (getrocknete Aprikosen haben z. B. deutlich mehr kcal/100g). Tag
-- 'quelle:kategorie-schaetzung' markiert das ehrlich, statt fälschlich
-- 'quelle:bls'/'quelle:usda' zu behaupten. Für einen Familien-Speiseplan
-- (keine klinische Ernährungsberatung) bewusst akzeptiert — mehr Zutaten
-- für die Rezept-Zuordnung wiegt hier schwerer als Nährwert-Präzision pro
-- Variante.
insert into ingredients (
  name, slug, base_unit, department_id, density_g_ml,
  kcal_100, protein_100, carbs_100, fat_100, fiber_100,
  iron_mg_100, calcium_mg_100, season_months, tags
) values
